import java.util.LinkedHashSet;import java.util.Set;public class TrainConsistManagementApp {    public static void main(String[] args) {        System.out.println("=== Train Consist Management App (UC5) ===");        Set<String> trainFormation = new LinkedHashSet<>();        trainFormation.add("Engine");        trainFormation.add("Sleeper");        trainFormation.add("Cargo");        trainFormation.add("Guard");        trainFormation.add("Sleeper");        System.out.println("Final train formation: " + trainFormation);        System.out.println("Train consist initialized with unique bogies in correct order.");    }}